struct TabBar {
    const char** tabNames;
    int tabCount;
    int* activeTab;
    Rectangle bounds;
};

void UpdateTabBar(TabBar& tabBar) {
    Vector2 mousePos = GetMousePosition();

    float tabWidth = tabBar.bounds.width / tabBar.tabCount;

    for (int i = 0; i < tabBar.tabCount; i++) {
        Rectangle tabRect = {
            tabBar.bounds.x + i * tabWidth,
            tabBar.bounds.y,
            tabWidth,
            tabBar.bounds.height
        };

        if (CheckCollisionPointRec(mousePos, tabRect) && IsMouseButtonReleased(MOUSE_LEFT_BUTTON)) {
            *tabBar.activeTab = i;
        }
    }
}

void DrawTabBar(const TabBar& tabBar) {
    float tabWidth = tabBar.bounds.width / tabBar.tabCount;

    for (int i = 0; i < tabBar.tabCount; i++) {
        Rectangle tabRect = {
            tabBar.bounds.x + i * tabWidth,
            tabBar.bounds.y,
            tabWidth,
            tabBar.bounds.height
        };

        bool isActive = (i == *tabBar.activeTab);
        Color bgColor = isActive ? Color{50, 50, 60} : Color{30, 30, 40};
        Color borderColor = isActive ? Color{100, 150, 200} : Color{50, 50, 50};

        DrawRectangleRec(tabRect, bgColor);
        DrawRectangleLinesEx(tabRect, 1, borderColor);

        // الخط السفلي للتبويب النشط
        if (isActive) {
            DrawLine(tabRect.x, tabRect.y + tabRect.height - 2,
                    tabRect.x + tabRect.width, tabRect.y + tabRect.height - 2,
                    Color{100, 150, 200});
        }

        // النص
        int textWidth = MeasureText(tabBar.tabNames[i], 14);
        DrawText(tabBar.tabNames[i],
                tabRect.x + (tabWidth - textWidth) / 2,
                tabRect.y + 12, 14,
                isActive ? Color{255, 255, 255} : Color{150, 150, 150});
    }
}

struct InventoryItem {
    int itemId;
    Texture2D icon;
    const char* name;
    int quantity;
    int slotX, slotY;
    int width, height;  // للعناصر متعددة الخانات
};

struct InventoryGrid {
    int cols, rows;
    float cellSize;
    float padding;
    Vector2 position;
    std::vector<InventoryItem> items;
    int selectedSlot;
    int hoveredSlot;
};

int GetSlotIndex(int col, int row, int cols) {
    return row * cols + col;
}

void DrawInventoryGrid(InventoryGrid& grid) {
    Vector2 mousePos = GetMousePosition();
    grid.hoveredSlot = -1;

    for (int row = 0; row < grid.rows; row++) {
        for (int col = 0; col < grid.cols; col++) {
            float x = grid.position.x + col * (grid.cellSize + grid.padding);
            float y = grid.position.y + row * (grid.cellSize + grid.padding);

            Rectangle cellRect = {x, y, grid.cellSize, grid.cellSize};
            int slotIndex = GetSlotIndex(col, row, grid.cols);

            // التحقق من التحويم
            bool isHovered = CheckCollisionPointRec(mousePos, cellRect);
            if (isHovered) grid.hoveredSlot = slotIndex;

            // لون الخلية
            Color cellColor = Color{40, 40, 50};
            if (isHovered) cellColor = Color{60, 60, 80};
            if (slotIndex == grid.selectedSlot) cellColor = Color{50, 70, 100};

            // رسم الخلية
            DrawRectangleRec(cellRect, cellColor);
            DrawRectangleLinesEx(cellRect, 1, Color{70, 70, 80});
        }
    }

    // رسم العناصر فوق الخلايا
    for (const auto& item : grid.items) {
        float x = grid.position.x + item.slotX * (grid.cellSize + grid.padding);
        float y = grid.position.y + item.slotY * (grid.cellSize + grid.padding);
        float width = item.width * grid.cellSize + (item.width - 1) * grid.padding;
        float height = item.height * grid.cellSize + (item.height - 1) * grid.padding;

        // خلفية العنصر
        Rectangle itemRect = {x + 2, y + 2, width - 4, height - 4};
        DrawRectangleRec(itemRect, Color{60, 50, 40});
        DrawRectangleLinesEx(itemRect, 1, Color{150, 120, 80});

        // أيقونة العنصر
        DrawTexturePro(item.icon, {0, 0, (float)item.icon.width, (float)item.icon.height},
                      {x + 4, y + 4, width - 8, height - 8}, {0, 0}, 0, Color{255, 255, 255});

        // الكمية
        if (item.quantity > 1) {
            char qtyText[16];
            sprintf(qtyText, "%d", item.quantity);
            DrawText(qtyText, x + width - 20, y + height - 18, 12, Color{255, 255, 255});
        }
    }
}

struct ModalDialog {
    bool isOpen;
    const char* title;
    const char* message;
    const char* confirmText;
    const char* cancelText;
    Rectangle bounds;
    bool* result;
};

void DrawModal(ModalDialog& modal) {
    if (!modal.isOpen) return;

    // تعتيم الخلفية
    DrawRectangle(0, 0, GetScreenWidth(), GetScreenHeight(), Color{0, 0, 0, 150});

    // النافذة
    DrawRectangleRounded(modal.bounds, 0.1f, 8, Color{40, 40, 50});
    DrawRectangleRoundedLines(modal.bounds, 0.1f, 8, Color{80, 80, 100});

    // العنوان
    int titleWidth = MeasureText(modal.title, 18);
    DrawText(modal.title,
            modal.bounds.x + (modal.bounds.width - titleWidth) / 2,
            modal.bounds.y + 20, 18, Color{255, 200, 100});

    // الرسالة
    int msgWidth = MeasureText(modal.message, 14);
    DrawText(modal.message,
            modal.bounds.x + (modal.bounds.width - msgWidth) / 2,
            modal.bounds.y + 60, 14, Color{200, 200, 200});

    // زر التأكيد
    Rectangle confirmBtn = {
        modal.bounds.x + modal.bounds.width / 2 - 110,
        modal.bounds.y + modal.bounds.height - 50,
        100, 35
    };
    bool confirmHover = CheckCollisionPointRec(GetMousePosition(), confirmBtn);
    DrawRectangleRec(confirmBtn, confirmHover ? Color{200, 80, 80} : Color{150, 50, 50});
    DrawText(modal.confirmText, confirmBtn.x + 25, confirmBtn.y + 10, 14, Color{255, 255, 255});

    // زر الإلغاء
    Rectangle cancelBtn = {
        modal.bounds.x + modal.bounds.width / 2 + 10,
        modal.bounds.y + modal.bounds.height - 50,
        100, 35
    };
    bool cancelHover = CheckCollisionPointRec(GetMousePosition(), cancelBtn);
    DrawRectangleRec(cancelBtn, cancelHover ? Color{80, 80, 80} : Color{50, 50, 50});
    DrawText(modal.cancelText, cancelBtn.x + 25, cancelBtn.y + 10, 14, Color{200, 200, 200});

    // التفاعل
    if (IsMouseButtonReleased(MOUSE_LEFT_BUTTON)) {
        if (confirmHover) {
            *modal.result = true;
            modal.isOpen = false;
        } else if (cancelHover) {
            *modal.result = false;
            modal.isOpen = false;
        }
    }
}

struct TreeNode {
    const char* name;
    bool isExpanded;
    bool isSelected;
    std::vector<TreeNode> children;
    int depth;
};

void DrawTreeNode(TreeNode& node, float& yOffset, float indent, float lineHeight) {
    Vector2 mousePos = GetMousePosition();

    float x = 20 + indent * node.depth;
    float y = yOffset;

    Rectangle rowRect = {x - 5, y, 300, lineHeight};
    bool isHovered = CheckCollisionPointRec(mousePos, rowRect);

    // خلفية الصف
    if (node.isSelected) {
        DrawRectangleRec(rowRect, Color{50, 80, 120});
    } else if (isHovered) {
        DrawRectangleRec(rowRect, Color{40, 40, 50});
    }

    // أيقونة التوسيع/الطي
    if (!node.children.empty()) {
        const char* expandIcon = node.isExpanded ? "▼" : "▶";
        DrawText(expandIcon, x, y + 4, 12, Color{150, 150, 150});

        // التفاعل مع الأيقونة
        Rectangle expandRect = {x, y, 20, lineHeight};
        if (isHovered && CheckCollisionPointRec(mousePos, expandRect) && IsMouseButtonReleased(MOUSE_LEFT_BUTTON)) {
            node.isExpanded = !node.isExpanded;
        }
    }

    // اسم العقدة
    DrawText(node.name, x + 20, y + 4, 14,
            node.isSelected ? Color{255, 255, 255} : Color{180, 180, 180});

    // تحديد العقدة
    if (isHovered && IsMouseButtonReleased(MOUSE_LEFT_BUTTON)) {
        node.isSelected = true;
    }

    yOffset += lineHeight;

    // رسم الأبناء
    if (node.isExpanded) {
        for (auto& child : node.children) {
            DrawTreeNode(child, yOffset, indent, lineHeight);
        }
    }
}
